def set_run_font(run, size: int = 14, bold: bool = False) -> None:
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(size)
    run.bold = bold


def format_paragraph(paragraph, *, heading_level: int | None = None) -> None:
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    fmt = paragraph.paragraph_format
    fmt.line_spacing = 1.5
    fmt.space_after = Pt(0)
    fmt.first_line_indent = Cm(0 if heading_level else 1.25)
    for run in paragraph.runs:
        set_run_font(run, 16 if heading_level else 14, bool(heading_level))
    if heading_level:
        p_pr = paragraph._element.get_or_add_pPr()
        p_style = p_pr.find(qn("w:pStyle"))
        if p_style is None:
            p_style = OxmlElement("w:pStyle")
            p_pr.insert(0, p_style)
        p_style.set(qn("w:val"), "703" if heading_level == 1 else "704")


def insert_block(anchor, items: list[tuple[str, str]]) -> None:
    for kind, text in items:
        paragraph = anchor.insert_paragraph_before(text)
        format_paragraph(paragraph, heading_level=1 if kind == "h1" else 2 if kind == "h2" else None)


