def insert_extensions(doc: Document) -> None:
    anchors = {p.text.strip(): p for p in doc.paragraphs}
    if "2. Практическая часть" in anchors:
        insert_block(anchors["2. Практическая часть"], ANALYTIC_EXTENSION)
    if "3 Экономическая часть" in anchors:
        insert_block(anchors["3 Экономическая часть"], PRACTICAL_EXTENSION)


def fix_economy_heading_styles(doc: Document) -> None:
    for paragraph in doc.paragraphs:
        text = paragraph.text.strip()
        if text == "3 Экономическая часть":
            format_paragraph(paragraph, heading_level=1)
        elif text in {
            "3.1 Комплекс работ по разработке",
            "3.2 Определение затрат на разработку веб-сайта",
            "3.3 Оценка экономической эффективности",
        }:
            format_paragraph(paragraph, heading_level=2)


def main() -> None:
    doc = Document(SOURCE)
    insert_extensions(doc)
    fix_economy_heading_styles(doc)
    doc.save(OUTPUT)


if __name__ == "__main__":
    main()
